-/// Destroy instance after use (synchronous)
-fn destroyInstance(instance: PooledInstance) void {
-    c.wasm_runtime_destroy_exec_env(instance.exec_env);
-    c.wasm_runtime_deinstantiate(instance.module_inst);
-}
