-        .bytecode_len = bytecode_len,
-        .global_state_offset = @intCast(header_size + bytecode_len),
-        .global_state_len = 0, // No global state
-        .polyfills_hash = polyfills_hash,
-        .created_at = @intCast(std.time.milliTimestamp()),
