-        \\    env: {},
-        \\    argv: [],
-        \\    exit: function(code) { __wasi_proc_exit(code || 0); },
-        \\    cwd: function() { return '/'; },
-        \\    platform: 'wasi',
-        \\    arch: 'wasm32'
-        \\};
