-/// Read data from socket, args: socket_id, max_len, returns string or null for EOF
-pub fn nativeSocketRead(ctx: ?*qjs.JSContext, _: qjs.JSValue, argc: c_int, argv: [*c]qjs.JSValue) callconv(.c) qjs.JSValue {
