-    // Copy data
-    const copy_size = @min(old_size, new_size);
-    @memcpy(new_slice[0..copy_size], p[0..copy_size]);
-
-    return new_ptr;
-}
-
-pub fn qjs_malloc_usable_size(ptr: ?*const anyopaque) callconv(.c) usize {
